1	import {
2	  ImageModelV3,
3	  ImageModelV3File,
4	  SharedV3Warning,
5	} from '@ai-sdk/provider';
6	import {
7	  combineHeaders,
8	  convertBase64ToUint8Array,
9	  convertToFormData,
10	  createJsonResponseHandler,
11	  downloadBlob,
12	  postFormDataToApi,
13	  postJsonToApi,
14	} from '@ai-sdk/provider-utils';
15	import { OpenAIConfig } from '../openai-config';
16	import { openaiFailedResponseHandler } from '../openai-error';
17	import { openaiImageResponseSchema } from './openai-image-api';
18	import {
19	  OpenAIImageModelId,
20	  hasDefaultResponseFormat,
21	  modelMaxImagesPerCall,
22	} from './openai-image-options';
23	
24	interface OpenAIImageModelConfig extends OpenAIConfig {
25	  _internal?: {
26	    currentDate?: () => Date;
27	  };
28	}
29	
30	export class OpenAIImageModel implements ImageModelV3 {
31	  readonly specificationVersion = 'v3';
32	
33	  get maxImagesPerCall(): number {
34	    return modelMaxImagesPerCall[this.modelId] ?? 1;
35	  }
36	
37	  get provider(): string {
38	    return this.config.provider;
39	  }
40	
41	  constructor(
42	    readonly modelId: OpenAIImageModelId,
43	    private readonly config: OpenAIImageModelConfig,
44	  ) {}
45	
46	  async doGenerate({
47	    prompt,
48	    files,
49	    mask,
50	    n,
51	    size,
52	    aspectRatio,
53	    seed,
54	    providerOptions,
55	    headers,
56	    abortSignal,
57	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
58	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
59	  > {
60	    const warnings: Array<SharedV3Warning> = [];
61	
62	    if (aspectRatio != null) {
63	      warnings.push({
64	        type: 'unsupported',
65	        feature: 'aspectRatio',
66	        details:
67	          'This model does not support aspect ratio. Use `size` instead.',
68	      });
69	    }
70	
71	    if (seed != null) {
72	      warnings.push({ type: 'unsupported', feature: 'seed' });
73	    }
74	
75	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
76	
77	    if (files != null) {
78	      const { value: response, responseHeaders } = await postFormDataToApi({
79	        url: this.config.url({
80	          path: '/images/edits',
81	          modelId: this.modelId,
82	        }),
83	        headers: combineHeaders(this.config.headers(), headers),
84	        formData: convertToFormData<OpenAIImageEditInput>({
85	          model: this.modelId,
86	          prompt,
87	          image: await Promise.all(
88	            files.map(file =>
89	              file.type === 'file'
90	                ? new Blob(
91	                    [
92	                      file.data instanceof Uint8Array
93	                        ? new Blob([file.data as BlobPart], {
94	                            type: file.mediaType,
95	                          })
96	                        : new Blob([convertBase64ToUint8Array(file.data)], {
97	                            type: file.mediaType,
98	                          }),
99	                    ],
100	                    { type: file.mediaType },
101	                  )
102	                : downloadBlob(file.url),
103	            ),
104	          ),
105	          mask: mask != null ? await fileToBlob(mask) : undefined,
106	          n,
107	          size,
108	          ...(providerOptions.openai ?? {}),
109	        }),
110	        failedResponseHandler: openaiFailedResponseHandler,
111	        successfulResponseHandler: createJsonResponseHandler(
112	          openaiImageResponseSchema,
113	        ),
114	        abortSignal,
115	        fetch: this.config.fetch,
116	      });
117	
118	      return {
119	        images: response.data.map(item => item.b64_json),
120	        warnings,
121	        usage:
122	          response.usage != null
123	            ? {
124	                inputTokens: response.usage.input_tokens ?? undefined,
125	                outputTokens: response.usage.output_tokens ?? undefined,
126	                totalTokens: response.usage.total_tokens ?? undefined,
127	              }
128	            : undefined,
129	        response: {
130	          timestamp: currentDate,
131	          modelId: this.modelId,
132	          headers: responseHeaders,
133	        },
134	        providerMetadata: {
135	          openai: {
136	            images: response.data.map((item, index) => ({
137	              ...(item.revised_prompt
138	                ? { revisedPrompt: item.revised_prompt }
139	                : {}),
140	              created: response.created ?? undefined,
141	              size: response.size ?? undefined,
142	              quality: response.quality ?? undefined,
143	              background: response.background ?? undefined,
144	              outputFormat: response.output_format ?? undefined,
145	              ...distributeTokenDetails(
146	                response.usage?.input_tokens_details,
147	                index,
148	                response.data.length,
149	              ),
150	            })),
151	          },
152	        },
153	      };
154	    }
155	
156	    const { value: response, responseHeaders } = await postJsonToApi({
157	      url: this.config.url({
158	        path: '/images/generations',
159	        modelId: this.modelId,
160	      }),
161	      headers: combineHeaders(this.config.headers(), headers),
162	      body: {
163	        model: this.modelId,
164	        prompt,
165	        n,
166	        size,
167	        ...(providerOptions.openai ?? {}),
168	        ...(!hasDefaultResponseFormat(this.modelId)
169	          ? { response_format: 'b64_json' }
170	          : {}),
171	      },
172	      failedResponseHandler: openaiFailedResponseHandler,
173	      successfulResponseHandler: createJsonResponseHandler(
174	        openaiImageResponseSchema,
175	      ),
176	      abortSignal,
177	      fetch: this.config.fetch,
178	    });
179	
180	    return {
181	      images: response.data.map(item => item.b64_json),
182	      warnings,
183	      usage:
184	        response.usage != null
185	          ? {
186	              inputTokens: response.usage.input_tokens ?? undefined,
187	              outputTokens: response.usage.output_tokens ?? undefined,
188	              totalTokens: response.usage.total_tokens ?? undefined,
189	            }
190	          : undefined,
191	      response: {
192	        timestamp: currentDate,
193	        modelId: this.modelId,
194	        headers: responseHeaders,
195	      },
196	      providerMetadata: {
197	        openai: {
198	          images: response.data.map((item, index) => ({
199	            ...(item.revised_prompt
200	              ? { revisedPrompt: item.revised_prompt }
201	              : {}),
202	            created: response.created ?? undefined,
203	            size: response.size ?? undefined,
204	            quality: response.quality ?? undefined,
205	            background: response.background ?? undefined,
206	            outputFormat: response.output_format ?? undefined,
207	            ...distributeTokenDetails(
208	              response.usage?.input_tokens_details,
209	              index,
210	              response.data.length,
211	            ),
212	          })),
213	        },
214	      },
215	    };
216	  }
217	}
218	
219	/**
220	 * Distributes input token details evenly across images, with the remainder
221	 * assigned to the last image so that summing across all entries gives the
222	 * exact total.
223	 */
224	function distributeTokenDetails(
225	  details:
226	    | { image_tokens?: number | null; text_tokens?: number | null }
227	    | null
228	    | undefined,
229	  index: number,
230	  total: number,
231	): { imageTokens?: number; textTokens?: number } {
232	  if (details == null) {
233	    return {};
234	  }
235	
236	  const result: { imageTokens?: number; textTokens?: number } = {};
237	
238	  if (details.image_tokens != null) {
239	    const base = Math.floor(details.image_tokens / total);
240	    const remainder = details.image_tokens - base * (total - 1);
241	    result.imageTokens = index === total - 1 ? remainder : base;
242	  }
243	
244	  if (details.text_tokens != null) {
245	    const base = Math.floor(details.text_tokens / total);
246	    const remainder = details.text_tokens - base * (total - 1);
247	    result.textTokens = index === total - 1 ? remainder : base;
248	  }
249	
250	  return result;
251	}
252	
253	type OpenAIImageEditInput = {
254	  /**
255	   * Allows to set transparency for the background of the generated image(s).
256	   * This parameter is only supported for `gpt-image-1`. Must be one of
257	   * `transparent`, `opaque` or `auto` (default value). When `auto` is used, the
258	   * model will automatically determine the best background for the image.
259	   *
260	   * If `transparent`, the output format needs to support transparency, so it
261	   * should be set to either `png` (default value) or `webp`.
262	   *
263	   */
264	  background?: 'transparent' | 'opaque' | 'auto';
265	  /**
266	   * The image(s) to edit. Must be a supported image file or an array of images.
267	   *
268	   * For `gpt-image-1`, each image should be a `png`, `webp`, or `jpg` file less
269	   * than 50MB. You can provide up to 16 images.
270	   *
271	   * For `dall-e-2`, you can only provide one image, and it should be a square
272	   * `png` file less than 4MB.
273	   *
274	   */
275	  image: Blob | Blob[];
276	  input_fidelity?: ('high' | 'low') | null;
277	  /**
278	   * An additional image whose fully transparent areas (e.g. where alpha is zero) indicate where `image` should be edited. If there are multiple images provided, the mask will be applied on the first image. Must be a valid PNG file, less than 4MB, and have the same dimensions as `image`.
279	   */
280	  mask?: Blob;
281	  /**
282	   * The model to use for image generation. Only `dall-e-2` and `gpt-image-1` are supported. Defaults to `dall-e-2` unless a parameter specific to `gpt-image-1` is used.
283	   */
284	  model?: 'dall-e-2' | 'gpt-image-1' | 'gpt-image-1-mini' | (string & {});
285	  /**
286	   * The number of images to generate. Must be between 1 and 10.
287	   */
288	  n?: number;
289	  /**
290	   * The compression level (0-100%) for the generated images. This parameter
291	   * is only supported for `gpt-image-1` with the `webp` or `jpeg` output
292	   * formats, and defaults to 100.
293	   *
294	   */
295	  output_compression?: number;
296	  /**
297	   * The format in which the generated images are returned. This parameter is
298	   * only supported for `gpt-image-1`. Must be one of `png`, `jpeg`, or `webp`.
299	   * The default value is `png`.
300	   *
301	   */
302	  output_format?: 'png' | 'jpeg' | 'webp';
303	  partial_images?: number | null;
304	  /**
305	   * A text description of the desired image(s). The maximum length is 1000 characters for `dall-e-2`, and 32000 characters for `gpt-image-1`.
306	   */
307	  prompt?: string;
308	  /**
309	   * The quality of the image that will be generated. `high`, `medium` and `low` are only supported for `gpt-image-1`. `dall-e-2` only supports `standard` quality. Defaults to `auto`.
310	   *
311	   */
312	  quality?: 'standard' | 'low' | 'medium' | 'high' | 'auto';
313	  /**
314	   * The format in which the generated images are returned. Must be one of `url` or `b64_json`. URLs are only valid for 60 minutes after the image has been generated. This parameter is only supported for `dall-e-2`, as `gpt-image-1` will always return base64-encoded images.
315	   */
316	  response_format?: 'url' | 'b64_json';
317	  /**
318	   * The size of the generated images. Must be one of `1024x1024`, `1536x1024` (landscape), `1024x1536` (portrait), or `auto` (default value) for `gpt-image-1`, and one of `256x256`, `512x512`, or `1024x1024` for `dall-e-2`.
319	   */
320	  size?: `${number}x${number}`;
321	  /**
322	   * Edit the image in streaming mode. Defaults to `false`. See the
323	   * [Image generation guide](https://platform.openai.com/docs/guides/image-generation) for more information.
324	   *
325	   */
326	  stream?: boolean;
327	  /**
328	   * A unique identifier representing your end-user, which can help OpenAI to monitor and detect abuse. [Learn more](https://platform.openai.com/docs/guides/safety-best-practices#end-user-ids).
329	   *
330	   */
331	  user?: string;
332	};
333	
334	async function fileToBlob(
335	  file: ImageModelV3File | undefined,
336	): Promise<Blob | undefined> {
