6	export function convertBase64ToUint8Array(base64String: string) {
7	  const base64Url = base64String.replace(/-/g, '+').replace(/_/g, '/');
8	  const latin1string = atob(base64Url);
9	  return Uint8Array.from(latin1string, byte => byte.codePointAt(0)!);
10	}
11	
12	export function convertUint8ArrayToBase64(array: Uint8Array): string {
13	  let latin1string = '';
14	
15	  // Note: regular for loop to support older JavaScript versions that
16	  // do not support for..of on Uint8Array
17	  for (let i = 0; i < array.length; i++) {
18	    latin1string += String.fromCodePoint(array[i]);
19	  }
20	
21	  return btoa(latin1string);
22	}
23	
24	export function convertToBase64(value: string | Uint8Array): string {
25	  return value instanceof Uint8Array ? convertUint8ArrayToBase64(value) : value;
26	}
