---

### Step 5 — Create `packages/pixelart/turbo.json`

Identical to `packages/luma/turbo.json`:

```json
{
  "extends": ["//"],
  "tasks": {
    "build": { "outputs": ["**/dist/**"] }
  }
}
```

---

### Step 6 — Create `packages/pixelart/vitest.node.config.js` and `vitest.edge.config.js`

**vitest.node.config.js** (identical to luma, environment: `'node'`):
```js
import { defineConfig } from 'vite';
import packageJson from './package.json';

export default defineConfig({
  test: { environment: 'node', include: ['**/*.test.ts', '**/*.test.tsx'] },
  define: { __PACKAGE_VERSION__: JSON.stringify(packageJson.version) },
});
```

**vitest.edge.config.js** (identical to luma, environment: `'edge-runtime'`):
```js
import { defineConfig } from 'vite';
import packageJson from './package.json';

export default defineConfig({
  test: { environment: 'edge-runtime', include: ['**/*.test.ts', '**/*.test.tsx'] },
  define: { __PACKAGE_VERSION__: JSON.stringify(packageJson.version) },
});
```

---

### Step 7 — Create `packages/pixelart/src/version.ts`

Identical to `packages/luma/src/version.ts`:

```typescript
declare const __PACKAGE_VERSION__: string | undefined;
export const VERSION: string =
  typeof __PACKAGE_VERSION__ !== 'undefined' ? __PACKAGE_VERSION__ : '0.0.0-test';
```

---

### Step 8 — Create `packages/pixelart/src/pixelart-image-settings.ts`

Defines the model IDs and the provider-specific image settings type:

```typescript
// https://api.pixelart.ai (fictional)
export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | (string & {});

/** Visual style of the generated pixel art image. */
export type PixelArtStyle = 'pixel' | 'retro' | '8bit';

/**
 * Provider-specific settings for PixelArt image generation.
 * Pass via providerOptions: { pixelart: { ... } }
 */
export interface PixelArtImageSettings {
  /**
   * Visual rendering style.
   * - `pixel`: Clean, modern pixel art style.
   * - `retro`: Classic retro video-game aesthetic.
   * - `8bit`: Old-school 8-bit palette limited style.
   * Default: `'pixel'`
   */
  style?: PixelArtStyle;

  /**
   * Pixel density (pixels per unit). Higher values produce finer details.
   * Must be a positive integer. Default: `8`.
   */
  pixelDensity?: number;
}
```

---

### Step 9 — Create `packages/pixelart/src/pixelart-image-model.ts`

Core image model implementation. Key design decisions:
- Uses `postJsonToApi` (synchronous JSON API, unlike Luma's async poll)
- Supports: `prompt`, `n`, `size`, `seed`, provider options `style` and `pixelDensity`
- Issues `unsupported` warnings for: `aspectRatio`, `files` (image editing), `mask`
- Returns base64 images as `string[]`
- Fictional API endpoint: `POST https://api.pixelart.ai/v1/images/generate`

**Fictional API request body:**
```json
{
  "prompt": "...",
  "n": 1,
  "size": "512x512",
  "style": "pixel",
  "pixel_density": 8,
  "seed": 42
}
```

**Fictional API response:**
```json
{
  "created": 1712345678,
  "data": [
    { "b64_json": "<base64>", "seed": 42 }
  ],
  "usage": {
    "input_tokens": 10,
    "output_tokens": 100,
    "total_tokens": 110
  }
}
```

```typescript
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt, n, size, aspectRatio, seed,
    providerOptions, headers, abortSignal, files, mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use `size` instead.' });
    }
    if (files != null && files.length > 0) {
      warnings.push({ type: 'unsupported', feature: 'input images',
        details: 'PixelArt does not support image editing. Only text-to-image is supported.' });
    }
    if (mask != null) {
      warnings.push({ type: 'unsupported', feature: 'mask',
        details: 'PixelArt does not support mask-based inpainting.' });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        n,
        ...(size != null ? { size } : {}),
