### Step 9 — Create `packages/pixelart/src/pixelart-image-model.ts`

Core image model implementation. Key design decisions:
- Uses `postJsonToApi` (synchronous JSON API, unlike Luma's async poll)
- Supports: `prompt`, `n`, `size`, `seed`, provider options `style` and `pixelDensity`
- Issues `unsupported` warnings for: `aspectRatio`, `files` (image editing), `mask`
- Returns base64 images as `string[]`
- Fictional API endpoint: `POST https://api.pixelart.ai/v1/images/generate`

**Fictional API request body:**
```json
{
  "prompt": "...",
  "n": 1,
  "size": "512x512",
  "style": "pixel",
  "pixel_density": 8,
  "seed": 42
}
```

**Fictional API response:**
```json
{
  "created": 1712345678,
  "data": [
    { "b64_json": "<base64>", "seed": 42 }
  ],
  "usage": {
    "input_tokens": 10,
    "output_tokens": 100,
    "total_tokens": 110
  }
}
```

```typescript
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt, n, size, aspectRatio, seed,
    providerOptions, headers, abortSignal, files, mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use `size` instead.' });
    }
    if (files != null && files.length > 0) {
      warnings.push({ type: 'unsupported', feature: 'input images',
        details: 'PixelArt does not support image editing. Only text-to-image is supported.' });
    }
    if (mask != null) {
      warnings.push({ type: 'unsupported', feature: 'mask',
        details: 'PixelArt does not support mask-based inpainting.' });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        n,
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        ...(pixelartOptions?.style != null ? { style: pixelartOptions.style } : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (e) => e.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
    });

    return {
      images: response.data.map((item) => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      usage: {
        inputTokens: response.usage?.input_tokens ?? undefined,
        outputTokens: response.usage?.output_tokens ?? undefined,
        totalTokens: response.usage?.total_tokens ?? undefined,
      },
    };
  }
}

// Response schema (minimal; flexible to API changes)
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
          seed: z.number().nullish(),
        }),
      ),
      usage: z.object({
        input_tokens: z.number().nullish(),
        output_tokens: z.number().nullish(),
        total_tokens: z.number().nullish(),
      }).nullish(),
    }),
  ),
);

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

// Provider options schema for runtime validation
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style for image generation.
       * - `pixel`: Clean modern pixel art.
       * - `retro`: Classic retro video-game aesthetic.
       * - `8bit`: Old-school 8-bit palette.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      /**
       * Pixel density (pixels per unit). Higher = finer detail. Default: 8.
       */
      pixelDensity: z.number().int().positive().nullish(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
```

---

### Step 10 — Create `packages/pixelart/src/pixelart-provider.ts`

Mirrors `packages/luma/src/luma-provider.ts`:
- Env var: `PIXELART_API_KEY`
- Default base URL: `https://api.pixelart.ai/v1`
- Provider string: `'pixelart.image'`
- User-agent suffix: `ai-sdk/pixelart/${VERSION}`
- `languageModel`, `embeddingModel`, `textEmbeddingModel` all throw `NoSuchModelError`

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction, loadApiKey, withoutTrailingSlash, withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
  textEmbeddingModel(modelId: string): never;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelart = createPixelArt();
```

