   * - `pixel`: Classic pixel art style.
   * - `retro`: Retro video-game inspired style.
   * - `8bit`: 8-bit color palette and sprite aesthetic.
   *
   * Defaults to `pixel`.
   */
  style?: PixelArtStyle;

  /**
   * The pixel density (pixels per unit) of the generated image.
   * Higher values produce more detailed pixel art.
   * Must be a positive number.
   *
   * @example 8   // coarse, classic 8-bit look
   * @example 16  // medium detail
   * @example 32  // fine-grained pixel art
   */
  pixelDensity?: number;
}

